71#JZ:/**
72#TJ: * Resolve the GSD executable for direct invocation without shell wrappers.
73#QZ: *
74#QK: * On Windows, npm installs a `.cmd` wrapper that just calls `node <entry>.js`.
75#BX: * Using `shell: true` to run .cmd files creates an extra cmd.exe process that
76#RT: * breaks signal propagation, triggers Node 22 DEP0190 warnings, and fails
77#BM: * when the path contains spaces (common in `C:\Users\First Last\...`).
78#JV: *
79#BJ: * Instead, we parse the .cmd wrapper to find the actual Node.js entry point
80#VY: * and invoke it directly: `node <entry.js> --mode rpc`.
81#VN: *
82#MK: * On Unix, `gsd` is typically a direct symlink to a JS file with a shebang,
83#PR: * so we can run it directly.
84#RY: */
85#MJ:function resolveGsdPath(hint?: string): { command: string; args: string[]; useShell: boolean } {
86#WK:  // If user provided an explicit path, use it directly
87#TK:  if (hint && hint !== "gsd") {
88#KZ:    // If it's a .cmd file, parse it; otherwise assume it's directly executable
89#RX:    if (process.platform === "win32" && hint.toLowerCase().endsWith(".cmd")) {
90#WS:      const entry = parseWindowsCmdWrapper(hint);
91#WX:      if (entry) {
92#HX:        const nodePath = findNodeBinary();
93#TB:        return { command: nodePath, args: [entry], useShell: false };
94#WW:      }
95#PW:      // Couldn't parse .cmd — must use shell to execute it
96#HS:      return { command: hint, args: [], useShell: true };
97#WJ:    }
98#QS:    return { command: hint, args: [], useShell: false };
99#BX:  }
100#SR:
101#YY:  if (process.platform === "win32") {
102#YP:    return resolveGsdWindows();
103#KQ:  }
104#NJ:
105#VS:  return resolveGsdUnix();
106#JN:}
