108#VZ:/**
109#WN: * Find the Node.js binary path.
110#SJ: * In VS Code extension host, `process.execPath` is Electron, not Node.
111#XR: * We need the actual `node` binary to run GSD's JS entry point.
112#QV: */
113#SY:function findNodeBinary(): string {
114#YY:  // Try to find node via `where` (Windows) or `which` (Unix)
115#PP:  const cmd = process.platform === "win32" ? "where" : "which";
116#JQ:  try {
117#PH:    const result = spawnSync(cmd, ["node"], {
118#XB:      encoding: "utf-8",
119#TZ:      timeout: 5000,
120#XV:      windowsHide: true,
121#YM:    });
122#TS:    if (result.status === 0 && result.stdout) {
123#PK:      const firstMatch = result.stdout.trim().split(/\r?\n/)[0];
124#BB:      if (firstMatch && fs.existsSync(firstMatch)) {
125#PZ:        return firstMatch;
126#VH:      }
127#KM:    }
128#SN:  } catch { /* ignored */ }
129#HP:
130#QS:  // Fallback: assume node is on PATH
131#MB:  return "node";
132#PP:}
