134#MS:function resolveGsdWindows(): { command: string; args: string[]; useShell: boolean } {
135#SJ:  // Find the .cmd wrapper
136#VQ:  let cmdPath: string | null = null;
137#JQ:  try {
138#WQ:    const result = spawnSync("where", ["gsd.cmd"], {
139#XB:      encoding: "utf-8",
140#TZ:      timeout: 5000,
141#XV:      windowsHide: true,
142#SR:    });
143#TS:    if (result.status === 0 && result.stdout) {
144#PK:      const firstMatch = result.stdout.trim().split(/\r?\n/)[0];
145#BB:      if (firstMatch && fs.existsSync(firstMatch)) {
146#ZX:        cmdPath = firstMatch;
147#HQ:      }
148#BV:    }
149#SN:  } catch { /* ignored */ }
150#PY:
151#PK:  if (!cmdPath) {
152#JJ:    // Try without .cmd extension
153#VN:    try {
154#JH:      const result = spawnSync("where", ["gsd"], {
155#HT:        encoding: "utf-8",
156#RW:        timeout: 5000,
157#JX:        windowsHide: true,
158#KB:      });
159#QZ:      if (result.status === 0 && result.stdout) {
160#XN:        const lines = result.stdout.trim().split(/\r?\n/);
161#ZP:        for (const line of lines) {
162#JB:          if (line.toLowerCase().endsWith(".cmd") && fs.existsSync(line)) {
163#VQ:            cmdPath = line;
164#BJ:            break;
165#BX:          }
166#BQ:        }
167#XK:      }
168#ZT:    } catch { /* ignored */ }
169#NB:  }
170#HM:
171#XS:  if (cmdPath) {
172#RB:    // Parse the .cmd to find the actual node entry point
173#RH:    const entry = parseWindowsCmdWrapper(cmdPath);
174#JN:    if (entry) {
175#VW:      const nodePath = findNodeBinary();
176#JM:      return { command: nodePath, args: [entry], useShell: false };
177#JJ:    }
178#SZ:    // Couldn't parse — fall back to .cmd with shell
179#TV:    return { command: cmdPath, args: [], useShell: true };
180#NZ:  }
181#WS:
182#ZH:  // Last resort: "gsd" with shell
183#QN:  return { command: "gsd", args: [], useShell: true };
184#MZ:}
