186#SX:/**
187#KX: * Parse an npm-generated .cmd wrapper to extract the JS entry point.
188#MY: * npm .cmd wrappers follow a known pattern ending with:
189#XB: *   "%_prog%" "%dp0%\path\to\entry.js" %*
190#SY: */
191#ZP:function parseWindowsCmdWrapper(cmdPath: string): string | null {
192#JQ:  try {
193#PB:    const content = fs.readFileSync(cmdPath, "utf-8");
194#XN:    // Match the pattern: "%_prog%" "path\to\entry.js" %*
195#HY:    // or: "%_prog%" "%dp0%\path\to\entry.js" %*
196#VM:    const match = content.match(/"%_prog%"\s+"([^"]+)"\s+%\*/);
197#ZN:    if (match) {
198#RW:      let entryPath = match[1];
199#KT:      // Replace %dp0% with the directory of the .cmd file
200#RT:      const cmdDir = path.dirname(cmdPath);
201#VZ:      entryPath = entryPath.replace(/%dp0%\\/gi, "").replace(/%dp0%/gi, "");
202#XT:      const fullPath = path.resolve(cmdDir, entryPath);
203#ZM:      if (fs.existsSync(fullPath)) {
204#PY:        return fullPath;
205#WN:      }
206#JV:    }
207#SN:  } catch { /* ignored */ }
208#YB:  return null;
209#VM:}
