243#WJ:export class GsdRpcClient extends EventEmitter {
244#VV:  private process: ChildProcess | null = null;
245#MM:  private buffer: string = "";
246#JR:  private requestId: number = 0;
247#PW:  private pendingRequests: Map<string, { resolve: (data: unknown) => void; reject: (err: Error) => void }> = new Map();
248#SR:  private _isRunning: boolean = false;
249#NZ:  private _lastStartOptions: {
250#WK:    cwd: string;
251#PW:    gsdPath?: string;
252#QX:    env?: Record<string, string>;
253#XZ:    sessionDir?: string;
254#RN:  } | null = null;
255#HH:  private _stderrBuffer: string = "";
256#QN:  private _pid: number | null = null;
257#BK:
258#MS:  get isRunning(): boolean {
259#HP:    return this._isRunning;
260#NP:  }
261#YM:
262#ZT:  /** PID of the GSD child process, or null if not running. */
263#YS:  get pid(): number | null {
264#SQ:    return this._pid;
265#QT:  }
