267#NW:  /**
268#VW:   * Spawn the GSD process in RPC mode.
269#JX:   */
270#SH:  async start(options: {
271#WK:    cwd: string;
272#PW:    gsdPath?: string;
273#QX:    env?: Record<string, string>;
274#XZ:    sessionDir?: string;
275#KS:  }): Promise<void> {
276#HR:    if (this.process) {
277#BB:      await this.stop();
278#MS:    }
279#QY:
280#VR:    this._lastStartOptions = { ...options };
281#HM:    this._stderrBuffer = "";
282#QT:
283#HB:    const resolved = resolveGsdPath(options.gsdPath);
284#YN:    // Log the resolved spawn command for diagnostics
285#BP:    this.emit("log", `[rpc-client] Spawn: ${resolved.command} ${resolved.args.join(" ")} --mode rpc (shell: ${resolved.useShell})\n`);
286#KJ:    const args = [...resolved.args, "--mode", "rpc"];
287#HB:
288#SY:    if (options.sessionDir) {
289#RW:      args.push("--session-dir", options.sessionDir);
290#NV:    }
291#BV:
292#QW:    const env = {
293#QY:      ...sanitizeEnvForChildProcess(process.env),
294#PM:      ...(options.env || {}),
295#HB:      // Force color output off for RPC
296#XX:      NO_COLOR: "1",
297#YR:      FORCE_COLOR: "0",
298#KN:    };
299#XN:
300#HY:    this.process = spawn(resolved.command, args, {
301#HS:      cwd: options.cwd,
302#MZ:      env,
303#XS:      stdio: ["pipe", "pipe", "pipe"],
304#WX:      shell: resolved.useShell,
305#XV:      windowsHide: true,
306#VP:    });
307#RB:
308#QN:    this._pid = this.process.pid ?? null;
309#ZT:
310#ZM:    this._isRunning = true;
311#TS:    this.buffer = "";
312#NW:
313#TY:    // Read stdout line by line (JSONL) — cap buffer at 10MB to prevent OOM
314#JY:    const MAX_BUFFER_SIZE = 10 * 1024 * 1024;
315#ZR:    this.process.stdout?.on("data", (chunk: Buffer) => {
316#XW:      this.buffer += chunk.toString("utf8");
317#QW:      if (this.buffer.length > MAX_BUFFER_SIZE) {
318#PS:        this.emit("log", `[rpc-client] Buffer exceeded ${MAX_BUFFER_SIZE / 1024 / 1024}MB — resetting (possible runaway output)`);
319#ZX:        this.buffer = "";
320#SW:      }
321#QT:      this.processBuffer();
322#RS:    });
323#HY:
324#PH:    // Handle stream errors (broken pipe, etc.) — without this they become unhandled errors
325#RP:    this.process.stdout?.on("error", (err) => {
326#SH:      this.emit("log", `[rpc-client] stdout error: ${err.message}\n`);
327#YJ:    });
328#PY:    this.process.stderr?.on("error", (err) => {
329#SR:      this.emit("log", `[rpc-client] stderr error: ${err.message}\n`);
330#SW:    });
331#TT:
332#WQ:    // Forward stderr as log events and buffer for diagnostics
333#NM:    this.process.stderr?.on("data", (chunk: Buffer) => {
334#NH:      const text = chunk.toString("utf8");
335#YP:      // Keep last 2KB of stderr for exit diagnostics
336#WR:      this._stderrBuffer += text;
337#PY:      if (this._stderrBuffer.length > 2048) {
338#QB:        this._stderrBuffer = this._stderrBuffer.slice(-2048);
339#KX:      }
340#JB:      this.emit("log", text);
341#YH:    });
342#ZH:
343#MT:    this.process.on("exit", (code, signal) => {
344#TH:      this._isRunning = false;
345#ZZ:      this._pid = null;
346#PV:
347#KZ:      // Build a more descriptive error message
348#SB:      const stderrHint = this._stderrBuffer.trim();
349#JS:      let detail = `GSD process exited (code=${code}, signal=${signal})`;
350#NR:      if (stderrHint) {
351#XN:        // Take the last meaningful line from stderr
352#BS:        const lines = stderrHint.split(/\r?\n/).filter(Boolean);
353#SK:        const lastLine = lines[lines.length - 1] || "";
354#YZ:        if (lastLine) {
355#JV:          detail += `: ${lastLine}`;
356#WY:        }
357#WX:      }
358#SQ:
359#JH:      this.emit("exit", { code, signal, detail });
360#ZK:
361#XP:      // Reject all pending requests with the enriched error
362#NS:      for (const [, pending] of this.pendingRequests) {
363#SJ:        pending.reject(new Error(detail));
364#HB:      }
365#KT:      this.pendingRequests.clear();
366#XH:      this.process = null;
367#BP:    });
368#KX:
369#QR:    this.process.on("error", (err) => {
370#TH:      this._isRunning = false;
371#KY:      this.emit("error", err);
372#JM:    });
373#BT:  }
