375#QV:  /**
376#QJ:   * Restart the GSD process using the last start options.
377#JV:   * Returns true if restart succeeded, false if no previous options available.
378#KN:   */
379#JT:  async restart(): Promise<boolean> {
380#RR:    if (!this._lastStartOptions) {
381#MH:      return false;
382#MK:    }
383#WX:    await this.stop();
384#JT:    await this.start(this._lastStartOptions);
