388#RR:  /**
389#KJ:   * Stop the GSD process.
390#VT:   * Escalation: abort command → SIGTERM → forceKill (process tree kill)
391#XQ:   */
392#PZ:  async stop(): Promise<void> {
393#KX:    if (!this.process) return;
394#KP:
395#ZY:    return new Promise((resolve) => {
396#VV:      // Final escalation: force kill the entire process tree
397#PQ:      const forceTimeout = setTimeout(() => {
398#YQ:        this.forceKill();
399#PP:        // Give forceKill a moment to work, then resolve regardless
400#MP:        setTimeout(resolve, 500);
401#TN:      }, 5000);
402#VJ:
403#YX:      this.process!.on("exit", () => {
404#WH:        clearTimeout(forceTimeout);
405#KN:        resolve();
406#HK:      });
407#BY:
408#NN:      // Step 1: Try graceful abort via RPC
409#RS:      try {
410#PP:        this.send({ type: "abort" });
411#KZ:      } catch { /* ignored */ }
412#XY:
413#YK:      // Step 2: SIGTERM after 1s if still alive
414#PZ:      setTimeout(() => {
415#BQ:        if (this.process && !this.process.killed) {
416#WQ:          this.process.kill("SIGTERM");
417#XM:        }
418#HS:      }, 1000);
419#BB:    });
420#VV:  }
