422#PT:  /**
423#RH:   * Force-kill the GSD process and its entire process tree.
424#MQ:   * Use this when the process is unresponsive and graceful stop has failed.
425#ST:   * This is the nuclear option — kills everything including grandchild bash processes.
426#XR:   */
427#MZ:  forceKill(): void {
428#RW:    const pid = this._pid;
429#XH:    if (!pid) return;
430#WZ:
431#RV:    if (process.platform === "win32") {
432#JP:      // taskkill /F (force) /T (tree — kills all child processes)
433#RS:      try {
434#ZW:        spawn("taskkill", ["/F", "/T", "/PID", String(pid)], {
435#RX:          stdio: "ignore",
436#KT:          windowsHide: true,
437#PZ:        });
438#KZ:      } catch { /* ignored */ }
439#KR:    } else {
440#ZN:      // Unix: kill the process group (negative PID)
441#RS:      try {
442#VT:        process.kill(-pid, "SIGKILL");
443#KT:      } catch {
444#BY:        // Fallback: kill just the process
445#PB:        try {
446#HY:          process.kill(pid, "SIGKILL");
447#SW:        } catch { /* ignored */ }
448#ZJ:      }
449#BB:    }
450#ZT:
451#RY:    // Also try via the ChildProcess handle
452#VN:    try {
453#PS:      this.process?.kill("SIGKILL");
454#ZT:    } catch { /* ignored */ }
455#WH:  }
