457#ZY:  /**
458#TR:   * Send a raw command to the GSD process.
459#WY:   */
460#HY:  send(command: Record<string, unknown>): void {
461#VJ:    if (!this.process?.stdin?.writable) {
462#HY:      throw new Error("[GSD-ERR-021] GSD process is not running — cannot send command");
463#SM:    }
464#QS:
