466#MX:    this.process.stdin.write(line);
467#WX:  }
468#PW:
469#HT:  /**
470#HJ:   * Send a command and wait for its response.
471#QM:   * 
472#KS:   * Timeout handling:
473#YB:   * - "prompt", "steer", "follow_up" use no timeout (agent turns can run indefinitely)
474#WK:   * - All other commands use a 60-second timeout
475#WQ:   */
476#JP:  async request(command: Record<string, unknown>, timeoutMs?: number): Promise<unknown> {
477#HT:    const id = `req-${++this.requestId}`;
478#RB:    const commandWithId = { ...command, id };
479#XY:
480#ZR:    // Long-running commands get no timeout; others get 60s default
481#NM:    const noTimeoutCommands = ["prompt", "steer", "follow_up", "compact"];
482#MJ:    const effectiveTimeout = timeoutMs ?? (noTimeoutCommands.includes(command.type as string) ? 0 : 60000);
483#TX:
484#HQ:    return new Promise((resolve, reject) => {
485#HZ:      let timeoutHandle: ReturnType<typeof setTimeout> | null = null;
486#WZ:
487#PM:      const cleanup = () => {
488#BQ:        if (timeoutHandle) {
489#JM:          clearTimeout(timeoutHandle);
490#VM:          timeoutHandle = null;
491#VT:        }
492#QJ:        this.pendingRequests.delete(id);
493#VR:      };
494#SM:
495#MZ:      this.pendingRequests.set(id, {
496#WQ:        resolve: (data) => {
497#KT:          cleanup();
498#YB:          resolve(data);
499#MY:        },
500#MK:        reject: (err) => {
501#KT:          cleanup();
502#YP:          reject(err);
503#HX:        },
504#PK:      });
505#BP:
506#QJ:      if (effectiveTimeout > 0) {
507#BV:        timeoutHandle = setTimeout(() => {
508#KT:          cleanup();
509#WH:          reject(new Error(`[GSD-ERR-020] Request timed out after ${effectiveTimeout / 1000}s: ${command.type}`));
510#KB:        }, effectiveTimeout);
511#KX:      }
512#MV:
513#RS:      try {
514#MQ:        this.send(commandWithId);
515#QJ:      } catch (err) {
516#NT:        cleanup();
517#MV:        reject(err);
518#QV:      }
519#PZ:    });
520#KP:  }
